type OrderServer struct {
	mu     sync.RWMutex
	orders map[string]*Order
}

func NewOrderServer() *OrderServer {
	return &OrderServer{
		orders: make(map[string]*Order),
	}
}

func (s *OrderServer) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*OrderResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "at least one item is required")
	}

	id := fmt.Sprintf("order-%d", len(s.orders)+1)
	now := time.Now()

	var items []*OrderItem
	var total float64
	for _, item := range req.Items {
		oi := &OrderItem{
			ProductID: item.ProductId,
			Name:      item.Name,
			Quantity:  item.Quantity,
			Price:     item.Price,
		}
		items = append(items, oi)
		total += item.Price * float64(item.Quantity)
	}

	order := &Order{
		ID:        id,
		UserID:    req.UserId,
		Items:     items,
		Status:    "PENDING",
		Total:     total,
		CreatedAt: now,
		UpdatedAt: now,
	}
	s.orders[id] = order

	log.Printf("[OrderService] Created order: %s for user %s (total: %.2f)", order.ID, order.UserID, order.Total)
	return orderToResponse(order), nil
}

func (s *OrderServer) GetOrder(ctx context.Context, req *GetOrderRequest) (*OrderResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	order, ok := s.orders[req.OrderId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.OrderId)
	}

	log.Printf("[OrderService] Retrieved order: %s", order.ID)
	return orderToResponse(order), nil
}

func (s *OrderServer) UpdateOrderStatus(ctx context.Context, req *UpdateOrderStatusRequest) (*OrderResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[req.OrderId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.OrderId)
	}

	validTransitions := map[string][]string{
		"PENDING":    {"CONFIRMED", "CANCELLED"},
		"CONFIRMED":  {"SHIPPED", "CANCELLED"},
		"SHIPPED":    {"DELIVERED"},
		"DELIVERED":  {},
		"CANCELLED":  {},
	}

	allowed := false
	for _, s := range validTransitions[order.Status] {
		if s == req.Status {
			allowed = true
			break
		}
	}
	if !allowed {
		return nil, status.Errorf(codes.FailedPrecondition, "cannot transition from %s to %s", order.Status, req.Status)
	}

	order.Status = req.Status
	order.UpdatedAt = time.Now()

	log.Printf("[OrderService] Updated order %s status to %s", order.ID, order.Status)
	return orderToResponse(order), nil
}

func (s *OrderServer) ListOrdersByUser(ctx context.Context, req *ListOrdersByUserRequest) (*ListOrdersResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	var orders []*OrderResponse
	for _, o := range s.orders {
		if o.UserID == req.UserId {
			orders = append(orders, orderToResponse(o))
		}
	}

	log.Printf("[OrderService] Listed %d orders for user %s", len(orders), req.UserId)
	return &ListOrdersResponse{Orders: orders, Total: int32(len(orders))}, nil
}

func (s *OrderServer) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*OrderResponse, error) {
	return s.UpdateOrderStatus(ctx, &UpdateOrderStatusRequest{
		OrderId: req.OrderId,
		Status:  "CANCELLED",
	})
}

