type PaymentServer struct {
	mu       sync.RWMutex
	payments map[string]*Payment
}

func NewPaymentServer() *PaymentServer {
	return &PaymentServer{
		payments: make(map[string]*Payment),
	}
}

func (s *PaymentServer) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*PaymentResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if req.OrderId == "" || req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id and user_id are required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be positive")
	}

	// Check for duplicate payment
	for _, p := range s.payments {
		if p.OrderID == req.OrderId && p.Status == "COMPLETED" {
			return nil, status.Errorf(codes.AlreadyExists, "payment already processed for order %s", req.OrderId)
		}
	}

	id := fmt.Sprintf("pay-%d", len(s.payments)+1)
	currency := req.Currency
	if currency == "" {
		currency = "USD"
	}

	payment := &Payment{
		ID:        id,
		OrderID:   req.OrderId,
		UserID:    req.UserId,
		Amount:    req.Amount,
		Currency:  currency,
		Status:    "COMPLETED",
		Method:    req.Method,
		CreatedAt: time.Now(),
	}
	s.payments[id] = payment

	log.Printf("[PaymentService] Processed payment: %s for order %s (%.2f %s)", payment.ID, payment.OrderID, payment.Amount, payment.Currency)
	return paymentToResponse(payment), nil
}

func (s *PaymentServer) GetPayment(ctx context.Context, req *GetPaymentRequest) (*PaymentResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	payment, ok := s.payments[req.PaymentId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.PaymentId)
	}

	log.Printf("[PaymentService] Retrieved payment: %s", payment.ID)
	return paymentToResponse(payment), nil
}

func (s *PaymentServer) GetPaymentByOrder(ctx context.Context, req *GetPaymentByOrderRequest) (*PaymentResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	for _, p := range s.payments {
		if p.OrderID == req.OrderId {
			log.Printf("[PaymentService] Retrieved payment for order: %s", req.OrderId)
			return paymentToResponse(p), nil
		}
	}

	return nil, status.Errorf(codes.NotFound, "no payment found for order %s", req.OrderId)
}

func (s *PaymentServer) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*PaymentResponse, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	payment, ok := s.payments[req.PaymentId]
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.PaymentId)
	}

	if payment.Status != "COMPLETED" {
		return nil, status.Errorf(codes.FailedPrecondition, "can only refund completed payments, current status: %s", payment.Status)
	}

	payment.Status = "REFUNDED"

	log.Printf("[PaymentService] Refunded payment: %s", payment.ID)
	return paymentToResponse(payment), nil
}

func (s *PaymentServer) ListPaymentsByUser(ctx context.Context, req *ListPaymentsByUserRequest) (*ListPaymentsResponse, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	var payments []*PaymentResponse
	for _, p := range s.payments {
		if p.UserID == req.UserId {
			payments = append(payments, paymentToResponse(p))
		}
	}

	log.Printf("[PaymentService] Listed %d payments for user %s", len(payments), req.UserId)
	return &ListPaymentsResponse{Payments: payments, Total: int32(len(payments))}, nil
}

