// ============================================================
// Logging Interceptor
// ============================================================

func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	start := time.Now()
	log.Printf("[gRPC] --> %s", info.FullMethod)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		st, _ := status.FromError(err)
		log.Printf("[gRPC] <-- %s [%s] %v (%s)", info.FullMethod, st.Code(), err, duration)
	} else {
		log.Printf("[gRPC] <-- %s [OK] (%s)", info.FullMethod, duration)
	}

	return resp, err
}

// ============================================================
// Recovery Interceptor
// ============================================================

func recoveryUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (resp interface{}, err error) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("[gRPC] PANIC recovered in %s: %v", info.FullMethod, r)
			err = status.Errorf(codes.Internal, "internal server error")
		}
	}()
	return handler(ctx, req)
}

// ============================================================
// Main - Server Setup
// ============================================================

func main() {
	port := ":50051"

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with interceptors
	grpcServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			recoveryUnaryInterceptor,
			loggingUnaryInterceptor,
		),
	)

	// Register service implementations
	userServer := NewUserManagementServer()
	orderServer := NewOrderServer()
	paymentServer := NewPaymentServer()

	RegisterUserManagementServiceServer(grpcServer, userServer)
	RegisterOrderServiceServer(grpcServer, orderServer)
	RegisterPaymentServiceServer(grpcServer, paymentServer)

	// Enable gRPC reflection for development and testing
	// This allows tools like grpcurl, grpcui, Evans, and Postman
	// to discover services, methods, and message types dynamically
	reflection.Register(grpcServer)

	// Seed some test data for development
	seedTestData(userServer, orderServer, paymentServer)

	log.Println("========================================")
	log.Println("  Microservices gRPC Server (DEV)")
	log.Println("========================================")
	log.Printf("  Listening on %s", port)
	log.Println("  Reflection: ENABLED")
	log.Println("")
	log.Println("  Registered Services:")
	log.Println("    - microservices.UserManagementService")
	log.Println("    - microservices.OrderService")
	log.Println("    - microservices.PaymentService")
	log.Println("")
	log.Println("  Test with grpcurl:")
	log.Println("    grpcurl -plaintext localhost:50051 list")
	log.Println("    grpcurl -plaintext localhost:50051 describe")
	log.Println("    grpcurl -plaintext -d '{\"name\":\"John\",\"email\":\"john@example.com\"}' localhost:50051 microservices.UserManagementService/CreateUser")
	log.Println("========================================")

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

// seedTestData populates services with sample data for development
func seedTestData(userSvc *UserManagementServer, orderSvc *OrderServer, paymentSvc *PaymentServer) {
	ctx := context.Background()

	// Create sample users
	user1, _ := userSvc.CreateUser(ctx, &CreateUserRequest{
		Name:  "Alice Johnson",
		Email: "alice@example.com",
	})
	user2, _ := userSvc.CreateUser(ctx, &CreateUserRequest{
		Name:  "Bob Smith",
		Email: "bob@example.com",
	})
	_, _ = userSvc.CreateUser(ctx, &CreateUserRequest{
		Name:  "Charlie Brown",
		Email: "charlie@example.com",
	})

	// Create sample orders
	order1, _ := orderSvc.CreateOrder(ctx, &CreateOrderRequest{
		UserId: user1.UserId,
		Items: []*OrderItemRequest{
			{ProductId: "prod-1", Name: "Laptop", Quantity: 1, Price: 999.99},
			{ProductId: "prod-2", Name: "Mouse", Quantity: 2, Price: 29.99},
		},
	})
	order2, _ := orderSvc.CreateOrder(ctx, &CreateOrderRequest{
		UserId: user2.UserId,
		Items: []*OrderItemRequest{
			{ProductId: "prod-3", Name: "Keyboard", Quantity: 1, Price: 149.99},
		},
	})

	// Confirm first order
	orderSvc.UpdateOrderStatus(ctx, &UpdateOrderStatusRequest{
		OrderId: order1.OrderId,
		Status:  "CONFIRMED",
	})

	// Process payment for confirmed order
	paymentSvc.ProcessPayment(ctx, &ProcessPaymentRequest{
		OrderId:  order1.OrderId,
		UserId:   user1.UserId,
		Amount:   order1.Total,
		Currency: "USD",
		Method:   "credit_card",
	})

	// Process payment for second order
	paymentSvc.ProcessPayment(ctx, &ProcessPaymentRequest{
		OrderId:  order2.OrderId,
		UserId:   user2.UserId,
		Amount:   order2.Total,
		Currency: "USD",
		Method:   "paypal",
	})

	log.Println("[Seed] Test data loaded successfully")
}